import SwiftUI

// MARK: - Lightweight SVG path parser (supports M/L/H/V/C/S/Q/T/Z and lowercase relatives)
private enum SVGToken: Equatable {
    case command(Character)
    case number(Double)
}

private struct SVGPathParser {
    static func parse(viewBox: CGSize, d: String) -> (Path, CGSize) {
        var path = Path()
        let tokens = tokenize(d)
        var i = 0

        var current = CGPoint.zero
        var subpathStart = CGPoint.zero
        var lastControl: CGPoint? = nil
        var lastCommand: Character? = nil

        func nextNumber() -> Double? {
            while i < tokens.count {
                if case .number(let n) = tokens[i] {
                    i += 1
                    return n
                }
                if case .command = tokens[i] { return nil }
                i += 1
            }
            return nil
        }

        func readPoint(relative: Bool) -> CGPoint? {
            guard let x = nextNumber(), let y = nextNumber() else { return nil }
            let p = CGPoint(x: x, y: y)
            if relative {
                return CGPoint(x: current.x + p.x, y: current.y + p.y)
            }
            return p
        }

        while i < tokens.count {
            guard case .command(let c) = tokens[i] else { i += 1; continue }
            i += 1

            let isRelative = c.isLowercase
            let cmd = Character(c.uppercased())

            switch cmd {
            case "M":
                if let p = readPoint(relative: isRelative) {
                    path.move(to: p)
                    current = p
                    subpathStart = p
                    lastControl = nil
                    lastCommand = "M"
                }
                // Subsequent pairs are implicit L
                while let p = readPoint(relative: isRelative) {
                    path.addLine(to: p)
                    current = p
                    lastControl = nil
                    lastCommand = "L"
                }

            case "L":
                while let p = readPoint(relative: isRelative) {
                    path.addLine(to: p)
                    current = p
                }
                lastControl = nil
                lastCommand = "L"

            case "H":
                while let x = nextNumber() {
                    let nx = isRelative ? current.x + x : x
                    let p = CGPoint(x: nx, y: current.y)
                    path.addLine(to: p)
                    current = p
                }
                lastControl = nil
                lastCommand = "H"

            case "V":
                while let y = nextNumber() {
                    let ny = isRelative ? current.y + y : y
                    let p = CGPoint(x: current.x, y: ny)
                    path.addLine(to: p)
                    current = p
                }
                lastControl = nil
                lastCommand = "V"

            case "C":
                while true {
                    guard
                        let c1 = readPoint(relative: isRelative),
                        let c2 = readPoint(relative: isRelative),
                        let p = readPoint(relative: isRelative)
                    else { break }
                    path.addCurve(to: p, control1: c1, control2: c2)
                    current = p
                    lastControl = c2
                }
                lastCommand = "C"

            case "S":
                while true {
                    guard let c2 = readPoint(relative: isRelative),
                          let p = readPoint(relative: isRelative)
                    else { break }
                    let reflected: CGPoint
                    if let lc = lastControl, lastCommand == "C" || lastCommand == "S" {
                        reflected = CGPoint(x: 2 * current.x - lc.x, y: 2 * current.y - lc.y)
                    } else {
                        reflected = current
                    }
                    path.addCurve(to: p, control1: reflected, control2: c2)
                    current = p
                    lastControl = c2
                }
                lastCommand = "S"

            case "Q":
                while true {
                    guard let c1 = readPoint(relative: isRelative),
                          let p = readPoint(relative: isRelative)
                    else { break }
                    path.addQuadCurve(to: p, control: c1)
                    current = p
                    lastControl = c1
                }
                lastCommand = "Q"

            case "T":
                while true {
                    guard let p = readPoint(relative: isRelative) else { break }
                    let reflected: CGPoint
                    if let lc = lastControl, lastCommand == "Q" || lastCommand == "T" {
                        reflected = CGPoint(x: 2 * current.x - lc.x, y: 2 * current.y - lc.y)
                    } else {
                        reflected = current
                    }
                    path.addQuadCurve(to: p, control: reflected)
                    current = p
                    lastControl = reflected
                }
                lastCommand = "T"

            case "Z":
                path.closeSubpath()
                current = subpathStart
                lastControl = nil
                lastCommand = "Z"

            default:
                // Unsupported command (e.g. A). Skip numbers until next command.
                while i < tokens.count, case .number = tokens[i] { i += 1 }
            }
        }

        return (path, viewBox)
    }

    private static func tokenize(_ d: String) -> [SVGToken] {
        var tokens: [SVGToken] = []
        var i = d.startIndex

        func skipSeparators() {
            while i < d.endIndex {
                let ch = d[i]
                if ch == "," || ch == " " || ch == "\n" || ch == "\t" || ch == "\r" {
                    i = d.index(after: i)
                } else {
                    break
                }
            }
        }

        func readNumber() -> Double? {
            let start = i
            var hasAny = false
            var sawDot = false
            var sawExp = false

            if i < d.endIndex, (d[i] == "-" || d[i] == "+") {
                i = d.index(after: i)
            }

            while i < d.endIndex {
                let ch = d[i]
                if ch.isNumber {
                    hasAny = true
                    i = d.index(after: i)
                } else if ch == "." && !sawDot {
                    sawDot = true
                    i = d.index(after: i)
                } else if (ch == "e" || ch == "E") && !sawExp {
                    sawExp = true
                    i = d.index(after: i)
                    if i < d.endIndex, (d[i] == "-" || d[i] == "+") {
                        i = d.index(after: i)
                    }
                } else {
                    break
                }
            }

            guard hasAny else {
                i = start
                return nil
            }

            return Double(d[start..<i])
        }

        while i < d.endIndex {
            skipSeparators()
            if i >= d.endIndex { break }

            let ch = d[i]
            if ch.isLetter {
                tokens.append(.command(ch))
                i = d.index(after: i)
                continue
            }

            if let num = readNumber() {
                tokens.append(.number(num))
                continue
            }

            // Unhandled char, skip.
            i = d.index(after: i)
        }

        return tokens
    }
}

struct BrandIcons {
    private static func mergeParsedPaths(viewBox: CGSize, dStrings: [String]) -> Path {
        var combined = Path()
        for d in dStrings {
            let (p, _) = SVGPathParser.parse(viewBox: viewBox, d: d)
            combined.addPath(p)
        }
        return combined
    }

    private static func appendPolygon(points: String, to path: inout Path) {
        let tokens = points.split(whereSeparator: { $0.isWhitespace })
            .compactMap { token -> CGPoint? in
                let parts = token.split(separator: ",")
                guard parts.count == 2,
                      let x = Double(parts[0]),
                      let y = Double(parts[1]) else { return nil }
                return CGPoint(x: x, y: y)
            }
        guard let first = tokens.first else { return }
        path.move(to: first)
        for pt in tokens.dropFirst() {
            path.addLine(to: pt)
        }
        path.closeSubpath()
    }

